-- Mini Z and Me, Sand Play Activities (Ages 0–5)
-- Run in: Supabase Dashboard → SQL Editor

INSERT INTO activities (age, title, emoji, color, area, subject, duration, materials, steps, prior_stage, prior_desc, safety, ease_of_prep, is_custom) VALUES

-- AGE 0
(0,'Dry Sand Finger Trail','🏖️','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Fine dry sand in a shallow tray'],ARRAY['Fill a shallow tray with fine dry sand.','Gently guide baby''s finger through the sand slowly.','Name the sensation: soft, tickly, smooth.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Ensure sand is dust-free. Supervise so sand is not mouthed.',9,false),
(0,'Sand Rain','🌧️','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Fine sand','Small cup or funnel'],ARRAY['Fill a small cup with fine sand.','Raise it above baby''s feet and pour the sand gently down.','Watch baby''s reaction to the soft rain of sand.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Keep sand away from baby''s face. Supervise closely.',8,false),
(0,'Shell Treasure Tray','🐚','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Sand in a shallow tray','Various shells (half buried)'],ARRAY['Half bury shells in a shallow tray of sand.','Let baby reach and grasp for the visible shells.','Describe each shell: bumpy, smooth, curly.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Use shells too large to be swallowed. Always supervise.',8,false),
(0,'Textured Sand Mat','🖐️','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Different grit sandpapers','Cardboard frame or tray'],ARRAY['Stick different grades of sandpaper in sections of a frame.','Guide baby''s hand over each section in turn.','Name each texture: rough, scratchy, smooth.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Ensure edges are smooth. Supervise at all times.',8,false),
(0,'Sand and Water Contrast','💧','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Dry sand in one tray','Wet sand in another tray'],ARRAY['Place baby''s hand in dry sand first, then move to wet sand.','Let them feel the difference in texture and weight.','Name each: dry, crumbly, wet, clumping.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Supervise so sand is not mouthed.',9,false),
(0,'Buried Bells','🔔','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Jingle bells','Sand in a shallow tray'],ARRAY['Hide jingle bells just under the surface of the sand.','Let baby pat and press the sand surface.','Listen for the bells and dig to find them.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Ensure bells are too large to swallow. Always supervise.',7,false),
(0,'Sand Footprint Casting','👣','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Wet sand in a tray','Camera to photograph'],ARRAY['Fill a tray with wet, firm sand.','Gently press baby''s feet into the sand.','Lift away to reveal the footprint, photograph to keep.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Wash feet after. Supervise so sand is not mouthed.',8,false),
(0,'Sand and Pebble Sorting Tray','🪨','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Sand in a shallow tray','Smooth pebbles'],ARRAY['Fill a tray with a mix of sand and smooth pebbles.','Let baby explore, grasping pebbles and letting sand run through fingers.','Name each: pebble, stone, sand.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Use large, smooth pebbles only. Always supervise.',8,false),
(0,'Coloured Sand Watching','🌈','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Coloured sand in different colours','Clear jar'],ARRAY['Layer different coloured sands into a clear jar.','Hold the jar up for baby to watch the colours.','Tip gently and watch the colours shift.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Ensure jar is sealed. Never leave baby alone with jar.',8,false),
(0,'Sand Waterfall','⌛','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Fine sand','Funnel or rolled paper tube'],ARRAY['Hold a funnel above a tray.','Pour fine sand through slowly and let baby watch it fall.','Describe: falling, flowing, soft.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Keep sand away from baby''s face.',9,false),
(0,'Treasure Tin','🎁','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Small tins with lids','Sand in a tray'],ARRAY['Bury small tins (with lids) just under the sand surface.','Help baby dig and find each tin.','Open the lid together and look inside.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Ensure tins have no sharp edges. Always supervise.',7,false),
(0,'Herb Sensory Sand','🌿','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Dry sand','Dried lavender or chamomile','Shallow tray'],ARRAY['Mix dried herbs into the sand.','Let baby run fingers and hands through the scented sand.','Name the smell: lavender, flowers, sweet.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Supervise so sand is not mouthed.',8,false),
(0,'Sand Sifter Watch','⌛','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Sand','Sieve or sifter'],ARRAY['Hold the sieve full of sand above a tray.','Gently shake so sand falls through in a stream.','Let baby watch the falling sand from a safe distance.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Keep sand away from baby''s face.',9,false),
(0,'Warm Sand Tray','☀️','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Sun-warmed sand in a shallow tray'],ARRAY['Leave sand in the sun to warm up.','Let baby press both hands gently into the warm sand.','Describe: warm, soft, cosy.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Test temperature first, it should be pleasantly warm, not hot.',9,false),
(0,'Seashell Sound Shakers','🐚','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Shells in a sealed container','Sand tray'],ARRAY['Place shells in a sealed container with a few grains of sand.','Shake over the sand tray so baby can hear the sound.','Let baby reach for the shaker.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Ensure container is sealed and too large to swallow.',8,false),
(0,'Cold Sand vs Warm','🌡️','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Indoor cool sand','Outdoor sun-warmed sand','Two trays'],ARRAY['Set up cool indoor sand and warm outdoor sand in separate trays.','Let baby touch each tray in turn.','Name the contrast: cool, cold, warm.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Test temperature first. Supervise at all times.',8,false),
(0,'Muddy Sand Sludge','🟤','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Sand','Water','Shallow tray'],ARRAY['Mix sand and water to a thick sludge consistency.','Let baby pat and press both hands into the sludge.','Describe: wet, heavy, squelchy.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Supervise so mud is not mouthed. Wash hands after.',9,false),
(0,'Stamping in Sand','🖐️','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Wet sand in a tray','Simple shape blocks or hands'],ARRAY['Smooth the surface of wet sand.','Press a simple shape or baby''s hand into the sand.','Reveal the impression and describe the shape.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Supervise so sand is not mouthed.',9,false),
(0,'Sand and Water Table','💦','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Large shallow tray','Sand on one side','Water on the other'],ARRAY['Fill one half of a large tray with sand, one half with water.','Let baby reach and touch each side.','Describe what happens when they mix the two.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Always supervise near water. Supervise so sand is not mouthed.',8,false),
(0,'Buried Soft Toys','🧸','#f5c842','Sand Play · Sensory','Sand Play','5–15 min',ARRAY['Small plush toys','Sand in a deep tray'],ARRAY['Half bury small soft toys in the sand.','Let baby grip and pull them out.','Name each toy as it''s discovered.'],'Newborn reflexes','Up to now, baby''s sensory world has mostly been about being held and looked at. This is the start of exploring for themselves.','Use washable toys. Supervise so sand is not mouthed.',8,false),

-- AGE 1
(1,'Buried Treasure','💎','#f5c842','Sand Play · Sensory','Sand Play','10–20 min',ARRAY['Coins and gems (plastic)','Sand in a deep tray','Small spade or scoop'],ARRAY['Hide coins and gems throughout the sand.','Encourage child to dig and discover each piece.','Celebrate each find and collect in a bowl.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Use large plastic gems only, no choking hazards.',8,false),
(1,'Sand Kitchen','🥄','#f5c842','Sand Play · Sensory','Sand Play','10–20 min',ARRAY['Old pots and spoons','Sand','Leaves and pebbles'],ARRAY['Set up old pots and spoons in the sand.','Show how to scoop sand and make sand cakes.','Add leaves and pebbles as toppings, serve the cakes!'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Supervise so sand is not eaten.',9,false),
(1,'Footprint Walk','👣','#f5c842','Sand Play · Sensory','Sand Play','10–20 min',ARRAY['Wet sand in a large tray or sandpit'],ARRAY['Smooth the wet sand surface flat.','Encourage child to walk a trail across it with bare feet.','Look back and count the footprints left behind.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Wash feet after. Supervise so sand is not mouthed.',9,false),
(1,'Sand Painting','🎨','#f5c842','Sand Play · Sensory','Sand Play','10–20 min',ARRAY['Wet sand base in a tray','Dry coloured sand','Spoon or funnel'],ARRAY['Spread wet sand flat in a tray.','Sprinkle dry coloured sand on top in patterns.','Use a spoon or funnel to draw lines and shapes.'],'Baby (0–12 months)','As a baby, they mostly watched while you showed them things. Now they want to take the lead and make things happen for themselves.','Supervise so sand is not mouthed.',7,false),
